import { useEffect, useState } from "react";
import { Star, Quote } from "lucide-react";
import api from "../../lib/api";

const FALLBACK = [
  {
    id: "r1",
    author_name: "Andrei M.",
    location: "Cluj-Napoca",
    rating: 5,
    text: "Am turnat o terasă de aproape 100 mp cu beton amprentat. Rezultat impecabil, echipa foarte atentă la detalii. Recomand cu drag!",
  },
  {
    id: "r2",
    author_name: "Mihaela P.",
    location: "București",
    rating: 5,
    text: "Lucrare profesionistă pentru hala noastră — pardoseală elicopterizată perfect netedă, livrată la timp. Vom mai colabora.",
  },
  {
    id: "r3",
    author_name: "Cristian D.",
    location: "Brașov",
    rating: 5,
    text: "Ne-au făcut gardul cu beton verticalizat și arată ca piatra naturală. Vecinii întreabă constant cine a făcut lucrarea.",
  },
];

export default function Reviews() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    api
      .get("/reviews")
      .then((r) => setItems(r.data || []))
      .catch(() => setItems([]));
  }, []);

  const display = items.length > 0 ? items : FALLBACK;

  return (
    <section id="recenzii" data-testid="reviews-section" className="section bg-[#1C1A17] text-[#F9F7F3] relative">
      <div className="absolute inset-0 grain opacity-50 pointer-events-none" aria-hidden />
      <div className="container-x relative">
        <div className="grid lg:grid-cols-12 gap-10 mb-14 items-end">
          <div className="lg:col-span-7">
            <p className="text-xs uppercase tracking-[0.35em] text-[#E8E4D9]/70 mb-4">Recenzii</p>
            <h2 className="font-display text-4xl sm:text-5xl lg:text-6xl leading-[1.05]">
              Vorbele <em className="text-[#A44A3F]">clienților</em> noștri.
            </h2>
          </div>
          <div className="lg:col-span-4 lg:col-start-9 text-[#E8E4D9]/80 text-sm leading-relaxed">
            Fiecare proiect este o relație. Iată ce spun oamenii cu care am lucrat.
          </div>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-px bg-[#3B3833]">
          {display.map((r, i) => (
            <article
              key={r.id || i}
              data-testid={`review-${i}`}
              className="bg-[#1C1A17] p-8 flex flex-col"
            >
              <Quote className="w-6 h-6 text-[#A44A3F] mb-5" strokeWidth={1.5} />
              <p className="font-display text-2xl leading-snug mb-6">"{r.text}"</p>
              <div className="mt-auto flex items-center justify-between border-t border-[#3B3833] pt-5">
                <div>
                  <div className="text-sm font-medium">{r.author_name}</div>
                  {r.location && (
                    <div className="text-[11px] uppercase tracking-[0.22em] text-[#E8E4D9]/60 mt-1">
                      {r.location}
                    </div>
                  )}
                </div>
                <div className="flex gap-0.5">
                  {Array.from({ length: r.rating || 5 }).map((_, idx) => (
                    <Star key={idx} className="w-4 h-4 fill-[#A44A3F] text-[#A44A3F]" />
                  ))}
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
